@app.route("/documents/search", methods=["GET"])
def search_documents():
    owner_id = request.args.get("owner_id")
    status = request.args.get("status")
    tag = request.args.get("tag")
    q = request.args.get("q")
    limit = min(int(request.args.get("limit", 20)), 100)
    skip = max(int(request.args.get("skip", 0)), 0)

    query = {}
    if owner_id:
        query["owner_id"] = owner_id
    if status:
        query["status"] = status
    if tag:
        query["tags"] = tag
    if q:
        query["$or"] = [
            {"title": {"$regex": q, "$options": "i"}},
            {"content": {"$regex": q, "$options": "i"}},
        ]

    cursor = documents.find(query).sort("created_at", DESCENDING).skip(skip).limit(limit)
    results = [serialize_doc(d) for d in cursor]
    total = documents.count_documents(query)
    return jsonify({"total": total, "results": results}), 200


@app.route("/analytics/top-authors", methods=["GET"])
def top_authors():
    limit = min(int(request.args.get("limit", 10)), 50)
    pipeline = [
        {"$group": {"_id": "$owner_id", "document_count": {"$sum": 1}}},
        {"$sort": {"document_count": -1}},
        {"$limit": limit},
        {
            "$lookup": {
                "from": "user_profiles",
                "localField": "_id",
                "foreignField": "user_id",
                "as": "profile",
            }
        },
        {"$unwind": {"path": "$profile", "preserveNullAndEmptyArrays": True}},
        {
            "$project": {
                "_id": 0,
                "owner_id": "$_id",
                "document_count": 1,
                "name": "$profile.name",
                "email": "$profile.email",
                "role": "$profile.role",
            }
        },
    ]
    results = list(documents.aggregate(pipeline))
    return jsonify({"results": results}), 200


@app.route("/analytics/tag-summary", methods=["GET"])
def tag_summary():
    pipeline = [
        {"$unwind": "$tags"},
        {"$group": {"_id": "$tags", "count": {"$sum": 1}}},
        {"$sort": {"count": -1, "_id": 1}},
    ]
    results = list(documents.aggregate(pipeline))
    return jsonify({"results": results}), 200


