@app.route("/documents/bulk", methods=["POST"])
def bulk_insert_documents():
    data = request.get_json(force=True) or {}
    items = data.get("documents", [])
    if not isinstance(items, list) or not items:
        return jsonify({"error": "documents must be a non-empty list"}), 400

    now = datetime.utcnow()
    docs = []
    for item in items:
        if not item.get("owner_id") or not item.get("title") or not item.get("content"):
            return jsonify({"error": "each document requires owner_id, title, and content"}), 400
        docs.append({
            "owner_id": item["owner_id"],
            "title": item["title"],
            "content": item["content"],
            "status": item.get("status", "draft"),
            "tags": item.get("tags", []),
            "metadata": item.get("metadata", {}),
            "created_at": now,
            "updated_at": now,
        })

    result = documents.insert_many(docs)
    inserted = list(documents.find({"_id": {"$in": result.inserted_ids}}))
    return jsonify({"inserted_count": len(result.inserted_ids), "documents": [serialize_doc(d) for d in inserted]}), 201


